const input = $input.first().json;
const { token, products, marketplace_url, api_key } = input.body || input;

// Validate required fields
if (!token) {
  return [{ json: { error: true, code: 'MISSING_TOKEN', message: 'Token is required' } }];
}
if (!products || !Array.isArray(products) || products.length === 0) {
  return [{ json: { error: true, code: 'INVALID_PRODUCTS', message: 'Products array is required and must not be empty' } }];
}
if (products.length > 5000) {
  return [{ json: { error: true, code: 'TOO_MANY_PRODUCTS', message: 'Maximum 5000 products per upload' } }];
}

// Decode JWT (HS256) to extract vendor_id
try {
  const parts = token.split('.');
  if (parts.length !== 3) throw new Error('Invalid token format');
  const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());

  // Check expiry
  if (payload.exp && payload.exp < Math.floor(Date.now() / 1000)) {
    return [{ json: { error: true, code: 'TOKEN_EXPIRED', message: 'Token has expired' } }];
  }

  const vendor_id = payload.sub || payload.vendor_id || payload.user_id;
  if (!vendor_id) {
    return [{ json: { error: true, code: 'INVALID_TOKEN', message: 'Token missing subject' } }];
  }

  return [{ json: {
    error: false,
    vendor_id,
    products,
    marketplace_url: marketplace_url || null,
    api_key: api_key || null,
    token
  } }];
} catch (e) {
  return [{ json: { error: true, code: 'AUTH_FAILED', message: 'Token verification failed: ' + e.message } }];
}

const input = $input.first().json;
const products = input.products;

// Convert products to Mirakl Product Import format (CSV)
// Mirakl expects: category;identifier;shop-sku;product-title;product-description;...attributes
const requiredFields = ['shop_sku', 'product_title', 'category_code'];

// Validate all products have required fields
const errors = [];
products.forEach((p, i) => {
  requiredFields.forEach(f => {
    if (!p[f]) errors.push(`Product ${i}: missing ${f}`);
  });
});

if (errors.length > 0) {
  return [{ json: { error: true, code: 'VALIDATION_ERROR', message: errors.join('; '), vendor_id: input.vendor_id, marketplace_url: input.marketplace_url, api_key: input.api_key } }];
}

// Build CSV header from all unique keys across products
const allKeys = new Set();
products.forEach(p => Object.keys(p).forEach(k => allKeys.add(k)));

// Map internal field names to Mirakl field names
const fieldMap = {
  'shop_sku': 'shop_sku',
  'product_title': 'product-title',
  'product_description': 'product-description',
  'category_code': 'category',
  'brand': 'brand',
  'ean': 'product-id',
  'ean_type': 'product-id-type',
  'image_url_1': 'media-url',
  'internal_description': 'internal-description',
  'variant_group_code': 'variant-group-code'
};

// Collect all attribute keys (those not in fieldMap)
const attrKeys = [...allKeys].filter(k => !fieldMap[k]);
const csvHeaders = [...Object.values(fieldMap), ...attrKeys];
const csvSeparator = ';';

const headerLine = csvHeaders.join(csvSeparator);
const dataLines = products.map(p => {
  const row = [];
  // Mapped fields first
  Object.keys(fieldMap).forEach(internal => {
    let val = p[internal] || '';
    // Escape semicolons and quotes in values
    val = String(val).replace(/"/g, '""');
    if (val.includes(csvSeparator) || val.includes('"') || val.includes('\n')) {
      val = '"' + val + '"';
    }
    row.push(val);
  });
  // Extra attribute fields
  attrKeys.forEach(k => {
    let val = p[k] || '';
    val = String(val).replace(/"/g, '""');
    if (val.includes(csvSeparator) || val.includes('"') || val.includes('\n')) {
      val = '"' + val + '"';
    }
    row.push(val);
  });
  return row.join(csvSeparator);
});

const csvContent = headerLine + '\n' + dataLines.join('\n');

return [{ json: {
  error: false,
  csv_content: csvContent,
  product_count: products.length,
  vendor_id: input.vendor_id,
  marketplace_url: input.marketplace_url,
  api_key: input.api_key
} }];

const input = $input.first().json;
const prevData = $('Build Product CSV').first().json;

// Check if the HTTP request succeeded
const statusCode = input.statusCode || input.status;
const mirakl_success = statusCode >= 200 && statusCode < 300;
const import_id = mirakl_success ? (input.body?.import_id || input.data?.import_id || input.import_id || null) : null;

const sync_log_id = 'sync_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

return [{ json: {
  mirakl_success,
  import_id,
  sync_log_id,
  status_code: statusCode,
  error_message: !mirakl_success ? (input.body?.message || input.message || 'Mirakl API error') : null,
  vendor_id: prevData.vendor_id,
  product_count: prevData.product_count,
  marketplace_url: prevData.marketplace_url
} }];

const mirakl = $('Parse Mirakl Response').first().json;
const syncLogResponse = $input.first().json;

const sync_log_id = Array.isArray(syncLogResponse) ? syncLogResponse[0]?.id : (syncLogResponse.id || syncLogResponse[0]?.id || null);

if (mirakl.mirakl_success) {
  return [{ json: {
    success: true,
    import_id: mirakl.import_id,
    sync_log_id,
    product_count: mirakl.product_count,
    message: `${mirakl.product_count} products submitted to Mirakl for import`
  } }];
} else {
  return [{ json: {
    success: false,
    error: 'mirakl_upload_failed',
    message: mirakl.error_message || 'Failed to upload products to Mirakl',
    status_code: mirakl.status_code,
    sync_log_id
  } }];
}
